INSERT INTO public.project_operation_alerts (project_id, nome, severidade, significado, acao, sort_order) VALUES ('tupi', 'POS_OFFLINE', 'Alta', 'Maquininha sem comunicação por mais de 10 minutos. Possível falha de rede no lojista ou travamento do firmware.', 'Verificar status no portal de gestão de dispositivos e acionar suporte remoto.', 0);
INSERT INTO public.project_operation_alerts (project_id, nome, severidade, significado, acao, sort_order) VALUES ('tupi', 'TRANSACTION_TIMEOUT', 'Alta', 'Transação sem resposta da adquirente em mais de 30s. Pode indicar instabilidade no gateway.', 'Checar status da adquirente e logs do serviço payment-gateway.', 1);
