INSERT INTO public.project_operation_diagnostics (project_id, step_text, sort_order) VALUES ('tupi', '1. Verificar painel de status dos dispositivos POS no portal interno', 0);
INSERT INTO public.project_operation_diagnostics (project_id, step_text, sort_order) VALUES ('tupi', '2. Checar logs de transação no Kibana filtrando por terminal_id e status:failed', 1);
INSERT INTO public.project_operation_diagnostics (project_id, step_text, sort_order) VALUES ('tupi', '3. Confirmar se a falha é pontual (1 terminal) ou sistêmica (múltiplos terminais)', 2);
INSERT INTO public.project_operation_diagnostics (project_id, step_text, sort_order) VALUES ('tupi', '4. Verificar conectividade da adquirente nos dashboards de parceiros', 3);
INSERT INTO public.project_operation_diagnostics (project_id, step_text, sort_order) VALUES ('tupi', '5. Acionar o suporte remoto do hardware se o dispositivo não responder', 4);
INSERT INTO public.project_operation_diagnostics (project_id, step_text, sort_order) VALUES ('tupi', '6. Abrir ticket no sistema de suporte com evidências de logs para escalation', 5);
